// Obtém o primeiro item (os dados do funcionário retornados pela query)
const inputData = $input.first().json;

// 1. Captura e limpa as opções básicas que sempre existem
const cpf = inputData.cpf ? inputData.cpf.toString().replace(/\D/g, '') : null;
const birthdate = inputData.birthdate ? inputData.birthdate.split('T')[0] : null;

// 2. Monta uma lista de opções dinâmicas disponíveis para o sorteio
const opcoesDisponiveis = [];

if (cpf) {
  opcoesDisponiveis.push({ tipo: 'cpf', valor: cpf, label: 'CPF (apenas números)' });
}

if (birthdate) {
  // Converte AAAA-MM-DD para DD/MM/AAAA para facilitar a digitação do usuário
  const [ano, mes, dia] = birthdate.split('-');
  const dataFormatada = `${dia}/${mes}/${ano}`;
  opcoesDisponiveis.push({ tipo: 'data de nascimento', valor: dataFormatada, label: 'Data de Nascimento (DD/MM/AAAA)' });
}

// Trata o e-mail (pode vir como string ou array no JSON do n8n)
let email = null;
if (Array.isArray(inputData.email)) {
  email = inputData.email[0];
} else if (typeof inputData.email === 'string') {
  email = inputData.email;
}

// Apenas adiciona o e-mail se ele não for nulo e for um formato de teste ou válido
if (email && email.includes('@') && !email.includes('teste.com')) {
  opcoesDisponiveis.push({ tipo: 'e-mail corporativo', valor: email.toLowerCase().trim(), label: 'E-mail Corporativo' });
}

// 3. LÓGICA DE SORTEIO / SELEÇÃO
// Embaralha as opções disponíveis de forma aleatória
const opcoesEmbaralhadas = opcoesDisponiveis.sort(() => 0.5 - Math.random());

// Seleciona os dois desafios que serão usados no processo
const dado_1 = opcoesEmbaralhadas[0];
const dado_2 = opcoesEmbaralhadas[1] || opcoesEmbaralhadas[0]; // Fallback caso só tenha 1 opção válida

// Garante que o dado_2 seja estritamente diferente do dado_1 se houver uma 3ª opção disponível
const final_dado_2_tipo = dado_2.tipo !== dado_1.tipo ? dado_2.tipo : (opcoesEmbaralhadas[2]?.tipo || dado_2.tipo);
const final_dado_2_valor = dado_2.tipo !== dado_1.tipo ? dado_2.valor : (opcoesEmbaralhadas[2]?.valor || dado_2.valor);
const final_dado_2_label = dado_2.tipo !== dado_1.tipo ? dado_2.label : (opcoesEmbaralhadas[2]?.label || dado_2.label);

// 4. Retorna formatado incluindo o controle de estado inicial (flags)
return {
  employee_id: inputData.id_Employee,
  nome_usuario: inputData.name || "Colaborador",

  // Informações do Primeiro Desafio
  dado_solicitado_1: dado_1.tipo,
  valor_esperado_1: dado_1.valor,
  label_pergunta_1: dado_1.label,

  // Informações do Segundo Desafio
  dado_solicitado_2: final_dado_2_tipo,
  valor_esperado_2: final_dado_2_valor,
  label_pergunta_2: final_dado_2_label,

  // 🔹 Flags de Controle de Estado adicionadas diretamente no output
  flag_1: false,
  flag_2: false
};

// Obtém os dados do funcionário retornados pela busca por CPF
const inputData = $input.first().json;

// 1. Captura e limpa as opções restantes para o Dado 2
const birthdate = inputData.birthdate ? inputData.birthdate.split('T')[0] : null;
const email = inputData.email ? inputData.email.toString().toLowerCase().trim() : null;

const opcoesDisponiveis = [];

// Adiciona a data de nascimento se ela existir
if (birthdate) {
  const [ano, mes, dia] = birthdate.split('-');
  const dataFormatada = `${dia}/${mes}/${ano}`;
  opcoesDisponiveis.push({ tipo: 'data de nascimento', valor: dataFormatada, label: 'Data de Nascimento (DD/MM/AAAA)' });
}

// Apenas adiciona o e-mail se ele for válido e não for um e-mail de teste genérico
if (email && email.includes('@') && !email.includes('teste.com')) {
  opcoesDisponiveis.push({ tipo: 'e-mail corporativo', valor: email, label: 'E-mail Corporativo' });
}

// 2. LÓGICA DE SELEÇÃO DO DADO 2
// Caso o funcionário não tenha um e-mail válido cadastrado, o fallback será a Data de Nascimento
let dado_2 = opcoesDisponiveis[0]; 

// Se houver mais de uma opção (Data e E-mail válidos), faz um sorteio aleatório entre eles
if (opcoesDisponiveis.length > 1) {
  const opcoesEmbaralhadas = opcoesDisponiveis.sort(() => 0.5 - Math.random());
  dado_2 = opcoesEmbaralhadas[0];
}

// 3. Retorna o payload estruturado para salvar no Redis e enviar no WhatsApp
return {
  employee_id: inputData.id_employee,
  nome_usuario: inputData.name || "Colaborador",

  // 🔹 O Dado 1 já foi o CPF digitado e validado nesta etapa
  dado_solicitado_1: "cpf",
  valor_esperado_1: inputData.cpf.toString().replace(/\D/g, ''),
  label_pergunta_1: "CPF (apenas números)",

  // 🎲 O Dado 2 foi sorteado dinamicamente entre as opções restantes
  dado_solicitado_2: dado_2.tipo,
  valor_esperado_2: dado_2.valor,
  label_pergunta_2: dado_2.label,

  // 🔄 Controle de estado: flag_1 já nasce TRUE porque o CPF acabou de ser validado
  flag_1: true,
  flag_2: false
};

// 1. Captura o input atual que veio do Agente de IA / Switch de Intenção
const inputIA = $input.first().json.output;

// 2. Captura o estado da memória que foi salvo anteriormente no Redis através do nó Switch
const authControl = $('Switch').first().json.auth_control;

// Funções auxiliares de limpeza
const apenasNumeros = (txt) => txt ? txt.toString().replace(/\D/g, '') : '';
const limparTexto = (txt) => txt ? txt.toString().toLowerCase().trim() : '';

// 3. Identifica o tipo de dado que estamos validando neste momento (Mudado para dado_solicitado_2)
const tipoDadoEsperado = authControl.dado_solicitado_2; // 'cpf', 'data de nascimento' ou 'e-mail corporativo'[cite: 1]
let isValido = false;

// 4. Executa a validação baseada no tipo de dado
if (tipoDadoEsperado === 'e-mail corporativo') {
  // Validação de E-mail: ignora maiúsculas/minúsculas e espaços
  const emailUsuario = limparTexto(inputIA.valor_extraido);
  const emailBanco = limparTexto(authControl.valor_esperado_2); // Comparando com valor_esperado_2[cite: 1]

  if (emailUsuario !== '' && emailUsuario === emailBanco) {
    isValido = true;
  }
} else {
  // Validação de CPF ou Data de Nascimento: limpa pontos, barras e traços
  const numUsuario = apenasNumeros(inputIA.valor_extraido);
  const numBanco = apenasNumeros(authControl.valor_esperado_2); // Comparando com valor_esperado_2[cite: 1]

  if (numUsuario !== '' && numUsuario === numBanco) {
    isValido = true;
  }
}

// 5. Retorna o resultado estruturado para os próximos nós do fluxo
return {
  dado_2_valido: isValido, // Alimenta a condição do seu nó IF de validação do dado 2[cite: 1]

  // Repassa o objeto auth_control atualizado para salvar o estado final de sucesso no Redis
  auth_control: {
    ...authControl,
    flag_2: isValido ? true : authControl.flag_2 // Se acertou, a flag_2 vira true[cite: 1]
  }
};

